import { ResponsiveContainer, LineChart, Line, CartesianGrid, XAxis, YAxis, Tooltip } from 'recharts';

function LogisticDataFromOrders(orders) {
    const bucket = {};
    orders.forEach((order) => {
        if (!order.created_at) return;
        const created = new Date(order.created_at);
        if (Number.isNaN(created.getTime())) return;

        const key = created.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
        bucket[key] = (bucket[key] || 0) + 1;
    });

    return Object.entries(bucket)
        .map(([name, orders]) => ({ name, orders }))
        .sort((a, b) => new Date(a.name) - new Date(b.name));
}

function LogisticsGraph({ orders }) {
    const data = LogisticDataFromOrders(orders);

    return (
        <div style={{ width: '100%', height: 320 }}>
            <ResponsiveContainer>
                <LineChart data={data} margin={{ top: 20, right: 20, left: 0, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="name" />
                    <YAxis allowDecimals={false} />
                    <Tooltip />
                    <Line type="monotone" dataKey="orders" stroke="#2563eb" strokeWidth={3} dot={{ r: 3 }} />
                </LineChart>
            </ResponsiveContainer>
        </div>
    );
}

export default LogisticsGraph;
